parameters.request/body:
{
 "dataAreaId": "@{body('Create_Bill_of_Materials_Header')?['dataAreaId']}",
 "RouteId": "@{body('Create_Route_Header')?['RouteId']}",
 "OperationNumber": @{variables('varOperationNumber')},
 "NextRouteOperationNumber": @{if(
    equals(
        variables('varBOMPositions_ToProcess'),
        add(
            variables('varBOMPositions_Processed'), 
            1
        )
    ), 
    0, 
    add(
        variables('varOperationNumber'), 
        10
    )
)},
 "OperationId": "@{items('Apply_to_each_BOM_Position_[Production_Hour]_aggregated_by_Operation')?['OperationName']}"
}
